### Instruction:
Write an algorithm to find the minimum element in a sorted rotated array.

### Response:
// Find min element in rotated array
int findMin(int[] arr) {
  int n = arr.length;

  // Case 1: Not rotated //
  if (arr[0] <= arr[n - 1]) {
    return arr[0];
  }

  // Case 2: Rotated //
  int left = 0, right = n - 1;
  while (left <= right) {
    int mid = left + (right - left) / 2;

    if (mid > 0 && arr[mid] < arr[mid - 1]) {
      return arr[mid];
    }

    // Left is sorted //
    if (arr[mid] >= arr[left]) {
      left = mid + 1;
    }
    // Right is sorted //
    else {
      right = mid - 1;
    }
  }

  return -1;
}

// Example //
int[] arr = {4, 5, 6, 7, 0, 1, 2};
int min = findMin(arr);
System.out.println(min); // Output: 0

