### Instruction:
Create a program to solve a given Sudoku puzzle.

### Response:
import numpy as np

def solve_sudoku(board): 
    """
    Solve a given Sudoku puzzle
    """
    board = np.array(board) 

    empty_locations = [] 
    for i in range(9): 
        for j in range(9): 
            if board[i][j] == 0: 
                empty_locations.append((i, j)) 

    def check_valid(x, y, input):
        #Check row
        for i in range(9):
            if board[x][i] == input:
                return False
        #Check column
        for j in range(9):
            if board[j][y] == input:
                return False
        #Check block
        for i in range(3):  
            for j in range(3):  
                if board[i + x - x % 3][j + y - y % 3] == input: 
                    return False    
        return True

    def solve_board(empty_locations):
        if len(empty_locations) == 0: 
            return True

        for num in range(1, 10):
            if check_valid(empty_locations[0][0], empty_locations[0][1], num):
                board[empty_locations[0][0]][empty_locations[0][1]] = num 

                if solve_board(empty_locations[1:]): 
                    return True
                board[empty_locations[0][0]][empty_locations[0][1]] = 0 
        return False

    solve_board(empty_locations) 
    return board

### Instruction:
Create a program to take two strings and generate an edit distance score between them.

### Response:
def edit_distance(str1, str2): 
    m = len(str1) 
    n = len(str2)
    dp = [[0 for x in range(n + 1)] for x in range(m + 1)]
    for i in range(m + 1): 
        for j in range(n + 1): 
            if i == 0: 
                dp[i][j] = j
            elif j == 0: 
                dp[i][j] = i
            elif str1[i - 1] == str2[j - 1]: 
                dp[i][j] = dp[i - 1][j - 1]
            else: 
                dp[i][j] = 1 + min(dp[i][j - 1],
                                   dp[i - 1][j],
                                   dp[i - 1][j - 1])
    return dp[m][n]

