import React from 'react';
import { connect } from 'react-redux';
import { addTask, deleteTask, markComplete } from './actions/tasks';

let TodoList = ({ tasks, addTask, deleteTask, markComplete }) => {
 let input;
 return (
 <div>
 <form
 onSubmit = {e => {
 e.preventDefault()
 if (!input.value.trim()) {
 return
 }
 dispatch(addTask(input.value))
 input.value = ''
 }}
 >
 <input ref = {node => {
    input = node
 }} />
 <button type = "submit">
 Add Task
 </button>
 </form>
 <ul>
 {tasks.map(task =>
 <li key = {task.id}>
 <span>{task.text}</span>
 {!task.completed && (
 <button onClick = {() => markComplete(task.id)}>
 Complete Task
 </button>
 )}
 <button onClick = {() => deleteTask(task.id)} >
 Remove Task
 </button>
 </li>
 )}
 </ul>
 </div>
 );
};

const mapStateToProps = ({ tasks }) => ({
 tasks
});

const mapDispatchToProps = dispatch => ({
 addTask: text => dispatch(addTask(text)),
 deleteTask: id => dispatch(deleteTask(id)),
 markComplete: id => dispatch(markComplete(id))
});

TodoList = connect(
 mapStateToProps,
 mapDispatchToProps
)(TodoList);
export default TodoList;

