### Instruction:
Create a Javascript module to find and return the most frequently used words in a long text document.

### Response:
const findMostFrequentWords = (document) => {
 //remove punctuation and convert all words to lowercase
 let words = document.replace(/[^\w\s]/gi, '').toLowerCase().split(' ');

 //create a map of words to their frequencies
 let wordCountMap = {};
 for (let word of words) {
 if (!wordCountMap[word]) {
 wordCountMap[word] = 0;
 }
 wordCountMap[word]++;
 } 

 //find the word with the highest frequency
 let maxFrequency = 0;
 let mostFrequentWord;
 for (let word in wordCountMap) {
 if (wordCountMap[word] > maxFrequency) {
 maxFrequency = wordCountMap[word];
 mostFrequentWord = word;
 }
 }
 return mostFrequentWord;
};

