### Instruction:
Design an algorithm for calculating the number of palindromic substrings in a given string.

### Response:
def palindromicSubstrings(s):
    n = len(s)
    dp = [[0 for i in range(n)] for j in range(n)]
    count = 0

    for i in range(n):
        dp[i][i] = 1   
        count += 1

    for i in range(2, n+1):
        for j in range(n-i+1):
            k = i + j - 1
            if s[j] == s[k]:
                if i == 2:
                    dp[j][k] = 2  
                else:
                    dp[j][k] = dp[j + 1][k - 1] + 2
                count += dp[j][k]
            else:
                dp[j][k] = 0

    return count

