def permutations(nums):
    if len(nums) == 1:
        return [nums]
    else:
        all_perms = []
        for num in nums:
            arr = nums[:]
            arr.remove(num)
            perms = permutations(arr)
            for perm in perms:
                perm.insert(0, num)
                all_perms.append(perm)
