let list = [5, 4, 3, 2, 1];

let swap = (list, i, j) => {
  let temp = list[i];
  list[i] = list[j];
  list[j] = temp;
}

let bubbleSort = list => {
  let swapped;
  do {
    swapped = false;
    for (let i = 0; i < list.length; i++) {
      if (list[i] && list[i + 1] && list[i] > list[i + 1]) {
        swap(list, i, i + 1);
        swapped = true;
      }
    }
  } while (swapped);
  return list;
};

