### Instruction:
Develop a C++ program for solving the traveling salesman problem.

### Response:
#include <iostream>
#include <vector>
#include <limits>

const int MAX_CITIES = 3;

// Store the matrix of distances
int distance[MAX_CITIES][MAX_CITIES];

// Store the current path travelled
std::vector<int> path;

// Store the minimum distance from the source city to each other city
int minDistance[MAX_CITIES];

// Store the visited cities
bool visited[MAX_CITIES];

// Function to find the minimum distance from the source city
int findMinDistance() { 
 int min = std::numeric_limits<int>::max();
 int min_index;

 for (int v = 0; v < MAX_CITIES; v++)  {
 if (visited[v] == false && minDistance[v] <= min) { 
 min = minDistance[v]; 
 min_index = v; 
 } 
 } 

 return min_index; 
}

// Function to calculate the minimum total distance 
int calculateDistance() { 
 int min_dist = 0;

 for (int i = 0; i < MAX_CITIES; i++) {
 min_dist += minDistance[i]; 
 }

 return min_dist; 
}

// Function to solve the traveling salesman problem
void solveTsp() { 
 // Set all cities as not visited 
 for (int i = 0; i < MAX_CITIES; i++)  {
 visited[i] = false; 
 minDistance[i] = std::numeric_limits<int>::max(); 
 } 

 // Set the starting city as visited  
 visited[0] = true;

 // Set the distance of starting city from itself as 0 
 minDistance[0] = 0; 

 // Find the minimum distance from source city to each other city 
 for (int i = 0; i < MAX_CITIES - 1; i++) { 
 int min_index = findMinDistance(); 
 visited[min_index] = true; 

 for (int j = 0; j < MAX_CITIES; j++) { 
 if (!visited[j] && distance[min_index][j] && minDistance[min_index] != INT_MAX && minDistance[min_index]+distance[min_index][j] < minDistance[j]) { 
 minDistance[j] = minDistance[min_index] + distance[min_index][j]; 
 } 
 } 
 } 

 // Add the minimum distances of each city to the path 
 for (int i = 0; i < MAX_CITIES; i++) { 
 path.push_back(minDistance[i]); 
 } 

 // Print the minimum total distance 
 int total_dist = calculateDistance(); 
 std::cout << "Minimum Distance: " << total_dist << std::endl; 
} 

int main() {
 // Store the distances between each city 
 distance[0][0] = 0; 
 distance[0][1] = 2; 
 distance[0][2] = 10; 
 distance[1][0] = 2; 
 distance[1][1] = 0; 
 distance[1][2] = 4; 
 distance[2][0] = 10; 
 distance[2][1] = 4; 
 distance[2][2] = 0; 

 // Solve the traveling salesman problem
 solveTsp();

 return 0; 
}

