        System.out.println(fibonacci(10));
    }

    public static int fibonacci(int n){
        if(n == 0 || n == 1){
            return 1;
        }

        int prevPrev = 1;
        int prev = 1;
        int current = 0;

        for(int i = 2; i <= n; i++){
            current = prev + prevPrev;
            prevPrev = prev;
            prev = current;
        }

