class Node { 
    int data; 
    Node left, right; 

    Node(int value) { 
        data = value; 
        left = right = null; 
    } 
} 

class Tree {
    Node root; 

    Tree(int key) {
        root = new Node(key); 
    } 

    boolean containsValue(Node node, int value) {
        if (node == null) {
            return false; 
        } 

        if (node.data == value) { 
            return true; 
        } 

        boolean flag = containsValue(node.left, value) || 
                        containsValue(node.right, value); 

        return flag; 
    } 
}

