### Response:
#include <stdio.h>

#define ROW 3
#define COL 3

int multiply (int A[ROW][COL],
			  int B[ROW][COL])
{
	int C[ROW][COL];
	int i, j, k;

	for (i = 0; i < ROW; i++)
	{
	for (j = 0; j < COL; j++)
	{
		C[i][j] = 0;

		for (k = 0; k < ROW; k++)
		{
		  C[i][j] += A[i][k] * B[k][j];
		}
	}
	}


	return C;
}

