// function to calculate max difference 
int maxDifference(int arr[], int n) { 
    int maxDiff = -1;    // Initialize Result

    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {

            // Find the maximum difference 
            if (arr[j] - arr[i] > maxDiff) {
		maxDiff = arr[j] - arr[i]; 
            } 
        } 
    } 

    return maxDiff; 
}  

