### Instruction:
From a given linked list of integers, write a C++ function that finds the median value.

### Response:
#include <iostream>

// A linked list node
struct Node
{
 int data;
 Node* next;
};

/* Function to find median of a linked list*/
float findMedian(Node *head)
{
 // Base case
 if (head == NULL)
 return 0;

 Node* slow = head;
 Node* fast = head;

 while (fast->next != NULL && fast->next->next != NULL)
 {
 fast = fast->next->next;
 slow = slow->next;
 }

 if (fast->next == NULL)
 return slow->data;

 return (slow->data + slow->next->data) / 2.0;
}

// A utility function to create a new node
Node *newNode(int data)
{
 struct Node *temp = new Node;
 temp->data = data;
 temp->next = NULL;
 return temp;
}

/* Driver program to run above code */
int main()
{
 Node *head = newNode(10);
 head->next = newNode(8);
 head->next->next = newNode(6);
 head->next->next->next = newNode(15);
 head->next->next->next->next = newNode(12);

 printf("Median is %f", findMedian(head));

 return 0;
}

// Output: 10.5  (median of the given linked list 10, 8, 6, 15, 12)

