### Instruction:
Write a JavaScript program to validate a credit card number. The program should use the Luhn algorithm for verifying the validity of the credit card number.

### Response:
function isValidLuhn(num) {
 let arr = (num + '')
 .split('')
 .reverse()
 .map(x => parseInt(x));

 let lastDigit = arr.splice(0, 1)[0];
 let sum = arr.reduce((acc, val, i) => (i % 2 !== 0 ? acc + val : acc + ((val * 2) % 9) || 9), 0);

 sum += lastDigit;
 return sum % 10 === 0;
}

let cardNumber = '4111111111111111';

if (isValidLuhn(cardNumber)) {
 console.log('Valid credit card number');
} else {
 console.log('Invalid credit card number');
}

