function isAnagram(str1, str2) {
    if (str1.length !== str2.length) {
        return false;
    }
    const map = {};
    for (const char of str1) {
        if (map[char]) {
            map[char] += 1;
        } else {
            map[char] = 1;
        }
    }
    for (const char of str2) {
        if (!map[char]) {
            return false;
        } else {
            map[char] -= 1;
        }
    }
    return true;
}

